/**
 * Build the authorization URL for the Entra OAuth flow.
 */
export function buildAuthorizationUrl(
  config: EntraOAuthConfig,
  state: string,
  requestedScopes?: string[],
): string {
  const scopes = requestedScopes ?? config.scopes;
  const params = new URLSearchParams({
    client_id: config.clientId,
    response_type: "code",
    redirect_uri: config.redirectUri,
    scope: scopes.join(" "),
    state,
    response_mode: "query",
  });

  return `https://login.microsoftonline.com/${config.tenantId}/oauth2/v2.0/authorize?${params}`;
}

/**
 * Exchange an authorization code for tokens.
 */
export async function exchangeCodeForTokens(
  config: EntraOAuthConfig,
  code: string,
): Promise<{ accessToken: string; idToken?: string; expiresIn: number }> {
  const body = new URLSearchParams({
    client_id: config.clientId,
    client_secret: config.clientSecret,
    code,
    redirect_uri: config.redirectUri,
    grant_type: "authorization_code",
    scope: config.scopes.join(" "),
  });

  const res = await fetch(
    `https://login.microsoftonline.com/${config.tenantId}/oauth2/v2.0/token`,
    {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: body.toString(),
    },
  );

} /** * Exchange an authorization code for tokens. */ export async function exchangeCodeForTokens( config: EntraOAuthConfig, code: string, ): Promise<{ accessToken: string; idToken?: string; expiresIn: number }> { const body = new URLSearchParams({ client_id: config.clientId, client_secret: config.clientSecret, code, redirect_uri: config.redirectUri, grant_type: "authorization_code", scope: config.scopes.join(" "), }); const res = await fetch( `https://login.microsoftonline.com/${config.tenantId}/oauth2/v2.0/token`, { method: "POST", headers: { "Content-Type": "application/x-www-form-urlencoded" }, body: body.toString(), }, );

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Entra token exchange failed: ${res.status} ${text}`);
  }

  const data = (await res.json()) as {
    access_token: string;
    id_token?: string;
    expires_in: number;
  };

  return {
    accessToken: data.access_token,
    idToken: data.id_token,
    expiresIn: data.expires_in,
  };
}

/**
 * Validate an access token and extract claims.
 *
 * For production: use a proper JWT library with JWKS validation.
 * This implementation decodes the payload for scope extraction
 * and validates basic claims (issuer, audience, expiry).
 */
export function validateToken(
  config: EntraOAuthConfig,
  accessToken: string,
): TokenClaims | null {
  try {
    const parts = accessToken.split(".");
    if (parts.length !== 3) return null;

    const payload = JSON.parse(
      Buffer.from(parts[1], "base64url").toString("utf8"),
    ) as TokenClaims;

    // Validate issuer
    if (payload.iss !== config.issuer) {
      console.error(`Token issuer mismatch: ${payload.iss} !== ${config.issuer}`);
      return null;
    }

    // Validate audience
    if (payload.aud !== config.clientId) {
      console.error(`Token audience mismatch: ${payload.aud} !== ${config.clientId}`);
      return null;
    }

    // Validate expiry
    if (payload.exp * 1000 < Date.now()) {
      console.error("Token expired");
      return null;
    }

